consolidated_powershell_block.command:
# === Step 0 — Stage 5 Rollback Readiness Verification (~30s) ===

Write-Host "=== Stage 5 Rollback Readiness Pre-Flight ===" -ForegroundColor Cyan
Write-Host ""

$failures = @()

# Check 1: pre-platform-extract tag exists on BlarAI
$tag = (git -C C:\Users\mrbla\BlarAI tag | Select-String -Pattern '^pre-platform-extract$' -Quiet)
if ($tag) {
    Write-Host "[1] PASS: BlarAI tag 'pre-platform-extract' exists" -ForegroundColor Green
} else {
    Write-Host "[1] FAIL: BlarAI tag 'pre-platform-extract' NOT found" -ForegroundColor Red
    $failures += "Check 1: pre-platform-extract tag missing"
}

# Check 2: Bundle file exists
$bundlePath = 'C:\Users\mrbla\backups\BlarAI_pre_extract.bundle'
if (Test-Path $bundlePath) {
    $bundleSize = (Get-Item $bundlePath).Length
    Write-Host "[2] PASS: Bundle exists at $bundlePath ($([math]::Round($bundleSize/1MB,1)) MB)" -ForegroundColor Green
} else {
    Write-Host "[2] FAIL: Bundle NOT found at $bundlePath" -ForegroundColor Red
    $failures += "Check 2: Bundle file missing"
}

# Check 3: OOG zip exists
$oogPath = 'C:\Users\mrbla\backups\blarai_oog_20260424_171721.zip'
if (Test-Path $oogPath) {
    $oogSize = (Get-Item $oogPath).Length
    Write-Host "[3] PASS: OOG zip exists at $oogPath ($([math]::Round($oogSize/1MB,1)) MB)" -ForegroundColor Green
} else {
    Write-Host "[3] FAIL: OOG zip NOT found at $oogPath" -ForegroundColor Red
    $failures += "Check 3: OOG zip missing"
}

# Check 4: Bundle SHA256 matches Stage 0 manifest
$expectedBundleHash = 'C051CCFB8FBC6CA31E03F48537816F56CC3FAFC927CEAFAEC9825C9EC65D7707'
if (Test-Path $bundlePath) {
    Write-Host "[4] Computing bundle SHA256 (10-20s)..." -ForegroundColor Yellow
    $actualBundleHash = (Get-FileHash $bundlePath -Algorithm SHA256).Hash
    if ($actualBundleHash -eq $expectedBundleHash) {
        Write-Host "[4] PASS: Bundle SHA256 matches Stage 0 manifest" -ForegroundColor Green
    } else {
        Write-Host "[4] FAIL: Bundle SHA256 MISMATCH" -ForegroundColor Red
        Write-Host "    Expected: $expectedBundleHash" -ForegroundColor Red
        Write-Host "    Actual:   $actualBundleHash" -ForegroundColor Red
        $failures += "Check 4: Bundle SHA256 mismatch (corruption suspected)"
    }
} else {
    Write-Host "[4] SKIP: Bundle missing per [2]" -ForegroundColor Yellow
    $failures += "Check 4: Skipped due to Check 2 failure"
}

# Check 5: devplatform Phase C wake_launcher fix at be22a15
$phaseCFix = (git -C C:\Users\mrbla\devplatform log --oneline | Select-String -Pattern '^be22a15')
if ($phaseCFix) {
    Write-Host "[5] PASS: devplatform Phase C fix at be22a15 found in git log" -ForegroundColor Green
    Write-Host "    $phaseCFix" -ForegroundColor DarkGray
} else {
    Write-Host "[5] FAIL: devplatform Phase C fix at be22a15 NOT found in git log" -ForegroundColor Red
    $failures += "Check 5: Phase C wake_launcher fix missing from devplatform git history"
}

# Summary
Write-Host ""
if ($failures.Count -eq 0) {
    Write-Host "=== ALL 5 CHECKS PASS — Rollback parachute is intact. ===" -ForegroundColor Green
    Write-Host "Authorized to proceed to Step 1 (state.pause_fleet) per Pre-Flight." -ForegroundColor Green
} else {
    Write-Host "=== ROLLBACK READINESS VERIFICATION FAILURE ===" -ForegroundColor Red
    Write-Host "$($failures.Count) of 5 checks FAILED:" -ForegroundColor Red
    $failures | ForEach-Object { Write-Host "  - $_" -ForegroundColor Red }
    Write-Host ""
    Write-Host "STOP. Do NOT proceed to Step 1 (fleet pause)." -ForegroundColor Red
    Write-Host "Report to LA via chat with the FAIL line(s) above + per-check failure_disposition" -ForegroundColor Red
    Write-Host "guidance from Guide-#8 dispatch 5.0-GUIDE_RESPONSE_INSTANCE_8_ROLLBACK_READINESS_*.xml" -ForegroundColor Red
    Write-Host "Investigate root cause; restore missing/corrupted assets; re-run Step 0 before resuming." -ForegroundColor Red
    throw "Rollback readiness verification failed: $($failures -join '; ')"
}
